def parse_saml_response(saml_response):
    """Parse SAML response and extract assertion data"""
    try:
        # Decode and parse SAML response
        decoded_xml = base64.b64decode(saml_response)
        root = ET.fromstring(decoded_xml)
        
        # Find assertion
        assertion = root.find('.//saml:Assertion', namespaces=SAML_NAMESPACES)
        if assertion is None:
            raise ValueError("No assertion found in SAML response")
        
        # Extract user attributes
        attributes = {}
        attribute_statements = assertion.findall('.//saml:AttributeStatement', namespaces=SAML_NAMESPACES)
        
        for attr_statement in attribute_statements:
            for attr in attr_statement.findall('.//saml:Attribute', namespaces=SAML_NAMESPACES):
                attr_name = attr.get('Name')
                attr_values = attr.findall('.//saml:AttributeValue', namespaces=SAML_NAMESPACES)
                if attr_values:
                    attributes[attr_name] = [val.text for val in attr_values]
        
        # Extract subject (user identifier)
        subject = assertion.find('.//saml:Subject', namespaces=SAML_NAMESPACES)
        subject_name = None
        if subject is not None:
            name_id = subject.find('.//saml:NameID', namespaces=SAML_NAMESPACES)
            if name_id is not None:
                subject_name = name_id.text
        
        # Extract issuer
        issuer = assertion.find('.//saml:Issuer', namespaces=SAML_NAMESPACES)
        issuer_name = issuer.text if issuer is not None else None
        
        # Extract conditions
        conditions = assertion.find('.//saml:Conditions', namespaces=SAML_NAMESPACES)
        not_before = None
        not_on_or_after = None
        
        if conditions is not None:
            not_before = conditions.get('NotBefore')
            not_on_or_after = conditions.get('NotOnOrAfter')
        
        return {
            'assertion': assertion,
            'attributes': attributes,
            'subject': subject_name,
            'issuer': issuer_name,
            'not_before': not_before,
            'not_on_or_after': not_on_or_after,
            'valid': True
        }
        
    except Exception as e:
        return {'valid': False, 'error': str(e)}

def validate_saml_assertion(assertion_data):
    """Validate SAML assertion"""
    if not assertion_data['valid']:
        return False
    
    # Check if required elements are present
    if not assertion_data['subject']:
        return False
    
    # Validate time conditions if present
    now = datetime.utcnow()
    
    if assertion_data['not_before']:
        not_before_dt = datetime.strptime(assertion_data['not_before'], '%Y-%m-%dT%H:%M:%SZ')
        if now < not_before_dt:
            return False
    
    if assertion_data['not_on_or_after']:
        not_on_or_after_dt = datetime.strptime(assertion_data['not_on_or_after'], '%Y-%m-%dT%H:%M:%SZ')
        if now >= not_on_or_after_dt:
            return False
    
    return True

